  `reg_start` datetime NOT NULL COMMENT 'Bắt đầu nhận hồ sơ',
  `reg_end` datetime NOT NULL COMMENT 'Kết thúc nhận hồ sơ',
  `review_start` datetime NOT NULL COMMENT 'Bắt đầu xét tuyển',
