  `supp_reg_start` datetime DEFAULT NULL COMMENT 'Bắt đầu nhận hồ sơ bổ sung',
  `supp_reg_end` datetime DEFAULT NULL COMMENT 'Kết thúc nhận hồ sơ bổ sung',
  `supp_review_end` datetime DEFAULT NULL COMMENT 'Kết thúc xét bổ sung',
  `supp_enroll_deadline` datetime DEFAULT NULL COMMENT 'Hạn nhập học bổ sung',
  `supp_score_bonus` decimal(4,2) DEFAULT 0.00 COMMENT 'Điểm chuẩn bổ sung cao hơn bao nhiêu so với chính thức',
  `status` enum('draft','open','reviewing','enrolling','supplementary','completed') DEFAULT 'draft',
  `notes` text DEFAULT NULL,
