  `practice_periods` int(11) DEFAULT 0,
  `component_periods` varchar(50) DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- --------------------------------------------------------

--
-- Cấu trúc bảng cho bảng `tuition_configs`
--

CREATE TABLE `tuition_configs` (
  `id` int(11) NOT NULL,
  `semester_id` int(11) DEFAULT NULL COMMENT 'NULL = áp dụng cho tất cả học kỳ',
  `major_id` int(11) DEFAULT NULL COMMENT 'NULL = áp dụng cho tất cả ngành',
  `unit_price` decimal(12,2) NOT NULL COMMENT 'Đơn giá/TC',
  `note` varchar(255) DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp()
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

-- --------------------------------------------------------

--
-- Cấu trúc bảng cho bảng `tuition_invoices`
--

CREATE TABLE `tuition_invoices` (
  `id` int(11) NOT NULL,
  `period_id` int(11) NOT NULL DEFAULT 0,
  `student_id` int(11) NOT NULL COMMENT 'FK → students.id',
  `semester_id` int(11) NOT NULL COMMENT 'FK → semesters.id',
  `total_credits` int(11) NOT NULL DEFAULT 0 COMMENT 'Tổng tín chỉ đã đăng ký',
  `unit_price` decimal(12,2) NOT NULL DEFAULT 0.00 COMMENT 'Đơn giá/TC tại thời điểm lập hóa đơn',
  `gross_amount` decimal(14,2) NOT NULL DEFAULT 0.00 COMMENT 'Học phí gốc = total_credits × unit_price',
  `discount` decimal(14,2) NOT NULL DEFAULT 0.00 COMMENT 'Miễn giảm (học bổng, chính sách...)',
  `net_amount` decimal(14,2) NOT NULL DEFAULT 0.00 COMMENT 'Số tiền phải đóng = gross - discount',
  `paid_amount` decimal(14,2) NOT NULL DEFAULT 0.00 COMMENT 'Đã đóng',
  `due_date` date DEFAULT NULL COMMENT 'Hạn đóng học phí',
  `status` enum('draft','unpaid','partial','paid','overdue','waived') NOT NULL DEFAULT 'draft',
  `note` text DEFAULT NULL,
  `created_by` int(11) DEFAULT NULL COMMENT 'Admin tạo hóa đơn',
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp()
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

--
-- Đang đổ dữ liệu cho bảng `tuition_invoices`
--


-- --------------------------------------------------------

--
-- Cấu trúc bảng cho bảng `tuition_payments`
--

CREATE TABLE `tuition_payments` (
  `id` int(11) NOT NULL,
  `invoice_id` int(11) NOT NULL COMMENT 'FK → tuition_invoices.id',
  `amount` decimal(14,2) NOT NULL COMMENT 'Số tiền đóng lần này',
  `method` enum('cash','bank_transfer','online','other') NOT NULL DEFAULT 'cash' COMMENT 'Hình thức: tiền mặt, chuyển khoản, online, khác',
  `reference` varchar(100) DEFAULT NULL COMMENT 'Mã giao dịch / số biên lai',
  `note` varchar(255) DEFAULT NULL,
  `paid_by` int(11) DEFAULT NULL COMMENT 'Admin ghi nhận',
  `paid_at` timestamp NOT NULL DEFAULT current_timestamp()
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

-- --------------------------------------------------------

--
-- Cấu trúc bảng cho bảng `tuition_periods`
--

CREATE TABLE `tuition_periods` (
  `id` int(11) NOT NULL,
  `semester_id` int(11) NOT NULL COMMENT 'FK → semesters.id',
  `title` varchar(255) NOT NULL COMMENT 'VD: Thu học phí HK1 2025-2026',
  `open_date` date NOT NULL COMMENT 'Ngày bắt đầu thu (công bố cho SV)',
  `due_date` date NOT NULL COMMENT 'Hạn đóng học phí',
  `status` enum('draft','published','closed') NOT NULL DEFAULT 'draft' COMMENT 'draft=nháp, published=đã công bố, closed=đã đóng',
  `note` text DEFAULT NULL,
  `created_by` int(11) DEFAULT NULL,
  `published_at` timestamp NULL DEFAULT NULL COMMENT 'Thời điểm công bố',
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp()
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

--
-- Đang đổ dữ liệu cho bảng `tuition_periods`
--


-- --------------------------------------------------------

--
-- Cấu trúc bảng cho bảng `users`
--

CREATE TABLE `users` (
  `id` int(11) NOT NULL,
  `username` varchar(50) NOT NULL,
  `password` varchar(255) NOT NULL,
  `full_name` varchar(150) NOT NULL,
  `email` varchar(150) DEFAULT NULL,
  `phone` varchar(20) DEFAULT NULL,
  `address` varchar(255) DEFAULT NULL,
  `avatar` varchar(255) DEFAULT NULL,
  `role` enum('admin','staff','student','teacher') NOT NULL,
  `status` tinyint(4) DEFAULT 1,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp()
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

--
-- Đang đổ dữ liệu cho bảng `users`
--


