--
-- Cấu trúc bảng cho bảng `visit_logs`
--

CREATE TABLE `visit_logs` (
  `id` bigint(20) NOT NULL,
  `user_id` int(11) DEFAULT NULL COMMENT 'NULL = khách vãng lai',
  `role` varchar(20) DEFAULT NULL COMMENT 'admin, student, teacher, staff',
  `session_id` varchar(128) NOT NULL COMMENT 'PHP session ID',
  `ip` varchar(45) DEFAULT NULL,
  `user_agent` text DEFAULT NULL,
  `login_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `last_seen` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp()
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

